# E2-Skeptic three-route assess for S40-T1-A-E2
def assess(record: dict) -> str:
    required = {'stimulus', 'owner', 'environment', 'source', 'response', 'observed_ms', 'target_ms', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    try:
        ok = record["observed_ms"] <= record["target_ms"]
    except Exception:
        return 'REJECT_QA_SCENARIO'
    return 'PASS' if ok else 'REJECT_QA_SCENARIO'

record = {"case_id": "CASO-LIM-040-1A", **{"source":"ops","stimulus":"100 req/s","environment":"peak","response":"serve","observed_ms":280,"target_ms":300,"owner":"platform"}}
valid = dict(record)
invalid = dict(valid)
# adverse: invert first boolean flag if any
_flipped=False
for _k,_v in list(invalid.items()):
    if isinstance(_v,bool):
        invalid[_k]= (not _v)
        _flipped=True
        break
if not _flipped and isinstance(invalid.get('stages'), list):
    invalid['stages']=list(reversed(invalid['stages']))
elif not _flipped and 'dependencies' in invalid:
    invalid['dependencies']=[["domain","infrastructure"]]
incomplete={k:v for k,v in valid.items() if k != 'owner'}
print(assess(valid), assess(invalid), assess(incomplete))

