# E2-Skeptic packet-local for S40-T3-A-E2
def assess(record: dict) -> str:
    required = {"case_id", "contexts", "translations"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not bool(record["contexts"]["intake"] & record["contexts"]["er"])) and bool(record.get("translations")) else "SPLIT_CONTEXTS"

